mapper.select:
SELECT * FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
ORDER BY fetched_date DESC
LIMIT 1

SELECT MAX(fetched_date) FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}

SELECT * FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
  AND fetched_date >= #{startDate}
  AND fetched_date <= #{endDate}
ORDER BY fetched_date ASC

SELECT COUNT(1) > 0 FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
  AND fetched_date = #{fetchedDate}

mapper.update:
UPDATE exchange_rate
SET rate = #{rate},
    source = #{source},
    fetched_at = CURRENT_TIMESTAMP
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
  AND fetched_date = #{fetchedDate}

mapper.select:
SELECT fetched_date
FROM exchange_rate
WHERE base_currency = #{baseCurrency}
  AND target_currency = #{targetCurrency}
  AND source = #{source}
  AND fetched_date < #{beforeDate}
